// Search for correct Maule and El Mayor events
async function search(params) {
  const url = 'https://earthquake.usgs.gov/fdsnws/event/1/query?format=geojson' + 
    '&starttime=' + params.start + '&endtime=' + params.end +
    '&minmagnitude=' + params.minMag + '&orderby=magnitude&limit=3&reviewstatus=reviewed' +
    '&minlatitude=' + params.minLat + '&maxlatitude=' + params.maxLat +
    '&minlongitude=' + params.minLon + '&maxlongitude=' + params.maxLon;
  const r = await fetch(url);
  const d = await r.json();
  for (const f of d.features) {
    const p = f.properties;
    console.log(f.id, 'M' + p.mag, p.place, new Date(p.time).toISOString());
  }
}
console.log('=== Maule ===');
await search({start:'2010-02-27',end:'2010-02-28',minMag:8,minLat:-40,maxLat:-30,minLon:-75,maxLon:-70});
console.log('=== El Mayor ===');
await search({start:'2010-04-04',end:'2010-04-05',minMag:7,minLat:30,maxLat:34,minLon:-118,maxLon:-114});
" 2>&1

